import type { ComponentProps } from 'react';
import { AlertDialog as AlertDialogPrimitive } from '@base-ui/react/alert-dialog';
import { clsx } from 'clsx';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './AlertDialog.module.css';

const AlertDialog = AlertDialogPrimitive.Root;
const createAlertDialogHandle = AlertDialogPrimitive.createHandle;

function AlertDialogPortal({ className, ...props }: AlertDialogPrimitive.Portal.Props) {
  return (
    <AlertDialogPrimitive.Portal data-slot="alert-dialog-portal" className={className} {...props} />
  );
}

function AlertDialogTrigger({ className, render, ...props }: AlertDialogPrimitive.Trigger.Props) {
  return (
    <AlertDialogPrimitive.Trigger
      data-slot="alert-dialog-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
}

function AlertDialogBackdrop({ className, ...props }: AlertDialogPrimitive.Backdrop.Props) {
  return (
    <AlertDialogPrimitive.Backdrop
      data-slot="alert-dialog-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function AlertDialogViewport({ className, ...props }: AlertDialogPrimitive.Viewport.Props) {
  return (
    <AlertDialogPrimitive.Viewport
      data-slot="alert-dialog-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function AlertDialogPopup({ className, ...props }: AlertDialogPrimitive.Popup.Props) {
  return (
    <AlertDialogPrimitive.Popup
      data-slot="alert-dialog-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function AlertDialogTitle({ className, ...props }: AlertDialogPrimitive.Title.Props) {
  return (
    <AlertDialogPrimitive.Title
      data-slot="alert-dialog-title"
      className={mergeClassName(className, styles.title)}
      {...props}
    />
  );
}

function AlertDialogDescription({ className, ...props }: AlertDialogPrimitive.Description.Props) {
  return (
    <AlertDialogPrimitive.Description
      data-slot="alert-dialog-description"
      className={mergeClassName(className, styles.description)}
      {...props}
    />
  );
}

function AlertDialogClose({ className, ...props }: AlertDialogPrimitive.Close.Props) {
  return (
    <AlertDialogPrimitive.Close
      data-slot="alert-dialog-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    />
  );
}

function AlertDialogContent({ className, children, ...props }: AlertDialogPrimitive.Popup.Props) {
  return (
    <AlertDialogPortal>
      <AlertDialogBackdrop />
      <AlertDialogViewport>
        <AlertDialogPopup className={className} {...props}>
          {children}
        </AlertDialogPopup>
      </AlertDialogViewport>
    </AlertDialogPortal>
  );
}

function AlertDialogHeader({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="alert-dialog-header" className={clsx(styles.header, className)} {...props} />
  );
}

function AlertDialogFooter({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="alert-dialog-footer" className={clsx(styles.footer, className)} {...props} />
  );
}

function AlertDialogBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="alert-dialog-body" className={clsx(styles.body, className)} {...props} />;
}

function AlertDialogAction({ className, ...props }: AlertDialogPrimitive.Close.Props) {
  return <AlertDialogClose className={mergeClassName(className, styles.action)} {...props} />;
}

function AlertDialogCancel({ className, ...props }: AlertDialogPrimitive.Close.Props) {
  return <AlertDialogClose className={mergeClassName(className, styles.cancel)} {...props} />;
}

export {
  AlertDialog,
  createAlertDialogHandle,
  AlertDialogPortal,
  AlertDialogTrigger,
  AlertDialogBackdrop,
  AlertDialogViewport,
  AlertDialogPopup,
  AlertDialogTitle,
  AlertDialogDescription,
  AlertDialogClose,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogBody,
  AlertDialogFooter,
  AlertDialogAction,
  AlertDialogCancel,
};

@layer ui.components {
  .trigger,
  .close {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--alert-dialog-control-height, var(--size-lg));
    margin: 0;
    padding: var(--alert-dialog-control-padding-y, 0.5rem)
      var(--alert-dialog-control-padding-x, 0.875rem);
    border: var(--alert-dialog-control-border-width, var(--border-width-sm)) solid
      var(--alert-dialog-control-border-color, var(--color-border));
    border-radius: var(--alert-dialog-control-radius, var(--radius-md));
    background-color: var(--alert-dialog-control-bg, var(--color-background));
    color: var(--alert-dialog-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--alert-dialog-control-font-size, var(--text-md));
    line-height: var(--alert-dialog-control-line-height, var(--line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--alert-dialog-control-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --alert-dialog-focus-ring-width,
          var(--alert-dialog-control-border-width, var(--border-width-sm))
        )
        solid var(--alert-dialog-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(
            --alert-dialog-focus-ring-width,
            var(--alert-dialog-control-border-width, var(--border-width-sm))
          ) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--opacity-disabled);
    }
  }

  .trigger {
    color: var(--alert-dialog-trigger-color, var(--color-destructive));
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--alert-dialog-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--alert-dialog-backdrop-blur, 4px)));
    transition:
      opacity var(--alert-dialog-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--alert-dialog-backdrop-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  .viewport {
    box-sizing: border-box;
    position: fixed;
    z-index: var(--z-modal);
    inset: 0;
    display: grid;
    place-items: center;
    overflow-y: auto;
    overscroll-behavior: contain;
    padding: var(--alert-dialog-viewport-padding, var(--spacing-4));
  }

  .popup {
    box-sizing: border-box;
    position: relative;
    display: grid;
    gap: var(--spacing-4);
    width: min(
      var(--alert-dialog-width, 24rem),
      var(--alert-dialog-max-width, calc(100vw - var(--spacing-8, 2rem))),
      var(--available-width, calc(100vw - var(--spacing-8, 2rem)))
    );
    max-width: 100%;
    padding: var(--alert-dialog-padding, var(--spacing-6));
    border: var(--alert-dialog-border-width, var(--border-width-sm)) solid
      var(--alert-dialog-border-color, var(--color-border));
    border-radius: var(--alert-dialog-radius, var(--radius-lg));
    background-color: var(--alert-dialog-bg, var(--color-popover));
    color: var(--alert-dialog-color, var(--color-popover-foreground));
    box-shadow: var(--alert-dialog-shadow, var(--shadow-lg));
    transition:
      opacity var(--alert-dialog-transition, var(--transition-default)),
      transform var(--alert-dialog-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--alert-dialog-scale, var(--scale-popup)));
    }
  }

  .header {
    display: grid;
    gap: var(--alert-dialog-header-gap, var(--spacing-1));
  }

  .title {
    color: var(
      --alert-dialog-title-color,
      var(--alert-dialog-color, var(--color-popover-foreground))
    );
    font-size: var(--alert-dialog-title-font-size, var(--text-lg));
    font-weight: var(--alert-dialog-title-font-weight, var(--weight-semibold));
    line-height: var(--alert-dialog-title-line-height, var(--line-height-text-lg));
  }

  .description {
    color: var(
      --alert-dialog-description-color,
      var(--alert-dialog-muted-color, var(--color-muted-foreground))
    );
    font-size: var(--alert-dialog-description-font-size, var(--text-md));
    line-height: var(--alert-dialog-description-line-height, var(--line-height-text-md));
  }

  .title,
  .description {
    margin: 0;
  }

  .footer {
    display: flex;
    flex-wrap: wrap;
    justify-content: flex-end;
    gap: var(--alert-dialog-footer-gap, var(--spacing-2));
  }

  .cancel {
    border-color: var(--alert-dialog-cancel-border-color, var(--color-border));
    background-color: var(
      --alert-dialog-cancel-bg,
      var(--alert-dialog-control-bg, var(--color-background))
    );
    color: var(
      --alert-dialog-cancel-color,
      var(--alert-dialog-control-color, var(--color-foreground))
    );

    @media (hover: hover) {
      &:hover {
        background-color: var(
          --alert-dialog-cancel-bg-hover,
          var(--alert-dialog-control-bg-hover, var(--color-accent))
        );
      }
    }
  }

  .action {
    border-color: var(--alert-dialog-action-border-color, var(--color-primary));
    background-color: var(--alert-dialog-action-bg, var(--color-primary));
    color: var(--alert-dialog-action-color, var(--color-primary-foreground));

    @media (hover: hover) {
      &:hover {
        background-color: var(--alert-dialog-action-bg-hover, var(--color-foreground));
      }
    }
  }

  .body {
    color: var(
      --alert-dialog-description-color,
      var(--alert-dialog-muted-color, var(--color-muted-foreground))
    );
    font-size: var(--alert-dialog-description-font-size, var(--text-md));
    line-height: var(--alert-dialog-description-line-height, var(--line-height-text-md));
  }
}
